import java.util.*;

public class Solution {
    public static List<String> solve(int x) {
        List<String> result = new ArrayList<>();
        for (int i = 1; i <= x; i++) {
            if (i % 15 == 0) {
                result.add("FizzBuzz");
            } else if (i % 3 == 0) {
                result.add("Fizz");
            } else if (i % 5 == 0) {
                result.add("Buzz");
            } else {
                result.add(String.valueOf(i));
            }
        }
        return result;
    }
}
